#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding dental-assessment (14 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    full_name:string! \
    date_of_birth:date \
    nhs_number:string! \
    address:text! \
    telephone:string! \
    email:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    chief_complaint:text! \
    onset_date:date \
    duration:string! \
    severity:string! \
    pain_location:text! \
    pain_character:string! \
    aggravating_factors:text! \
    relieving_factors:text! \
    previous_treatment:text! \
    --htmx

cargo loco generate scaffold assessment_dental_history \
    assessment:references \
    last_dental_visit:date \
    visit_frequency:string! \
    previous_extractions:string! \
    extraction_details:text! \
    previous_orthodontics:string! \
    orthodontic_details:text! \
    previous_endodontics:string! \
    endodontic_details:text! \
    previous_prosthetics:string! \
    prosthetic_details:text! \
    oral_hygiene_routine:text! \
    brushing_frequency:string! \
    flossing_frequency:string! \
    mouthwash_use:string! \
    --htmx

cargo loco generate scaffold assessment_dmft \
    assessment:references \
    decayed_teeth:int \
    missing_teeth:int \
    filled_teeth:int \
    dmft_total:int \
    decayed_tooth_numbers:text! \
    missing_tooth_numbers:text! \
    filled_tooth_numbers:text! \
    caries_activity:string! \
    notes:text! \
    --htmx

cargo loco generate scaffold assessment_periodontal \
    assessment:references \
    gingival_status:string! \
    bleeding_on_probing:string! \
    bleeding_sites:text! \
    probing_depth_max:int \
    probing_depth_mean:double \
    clinical_attachment_loss:string! \
    furcation_involvement:string! \
    furcation_details:text! \
    tooth_mobility:string! \
    mobility_details:text! \
    plaque_index_score:double \
    calculus_present:string! \
    calculus_location:text! \
    gingival_recession:string! \
    recession_details:text! \
    --htmx

cargo loco generate scaffold assessment_oral_examination \
    assessment:references \
    soft_tissue_status:string! \
    soft_tissue_findings:text! \
    tongue_status:string! \
    tongue_findings:text! \
    floor_of_mouth_status:string! \
    floor_of_mouth_findings:text! \
    palate_status:string! \
    palate_findings:text! \
    buccal_mucosa_status:string! \
    buccal_mucosa_findings:text! \
    lymph_node_status:string! \
    lymph_node_findings:text! \
    tmj_status:string! \
    tmj_findings:text! \
    occlusion:string! \
    occlusion_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    has_cardiovascular_disease:string! \
    cardiovascular_details:text! \
    has_diabetes:string! \
    diabetes_type:string! \
    has_bleeding_disorder:string! \
    bleeding_disorder_details:text! \
    has_respiratory_disease:string! \
    respiratory_details:text! \
    has_hepatitis:string! \
    hepatitis_type:string! \
    has_hiv:string! \
    has_epilepsy:string! \
    has_osteoporosis:string! \
    bisphosphonate_use:string! \
    has_immunosuppression:string! \
    immunosuppression_details:text! \
    is_pregnant:string! \
    pregnancy_trimester:string! \
    tobacco_use:string! \
    alcohol_use:string! \
    other_conditions:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    takes_anticoagulants:string! \
    anticoagulant_name:string! \
    takes_antiplatelet:string! \
    antiplatelet_name:string! \
    takes_bisphosphonates:string! \
    bisphosphonate_name:string! \
    takes_immunosuppressants:string! \
    immunosuppressant_name:string! \
    takes_steroids:string! \
    steroid_name:string! \
    takes_antihypertensives:string! \
    antihypertensive_name:string! \
    local_anaesthetic_allergy:string! \
    anaesthetic_allergy_details:text! \
    latex_allergy:string! \
    antibiotic_allergy:string! \
    antibiotic_allergy_details:text! \
    other_medications:text! \
    other_allergies:text! \
    --htmx

cargo loco generate scaffold assessment_radiographic_findings \
    assessment:references \
    radiographs_taken:string! \
    radiograph_type:string! \
    radiograph_date:date \
    periapical_pathology:string! \
    periapical_details:text! \
    bone_loss_pattern:string! \
    bone_loss_severity:string! \
    bone_loss_details:text! \
    impacted_teeth:string! \
    impacted_teeth_details:text! \
    caries_detected:string! \
    caries_details:text! \
    root_resorption:string! \
    root_resorption_details:text! \
    other_pathology:string! \
    other_pathology_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    dmft_score:int! \
    decayed_count:int! \
    missing_count:int! \
    filled_count:int! \
    severity_level:string! \
    periodontal_risk:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
